alu_combinatorial:
wire [32:0] aluMinus = {1'b1, ~aluIn2} + {1'b0, aluIn1} + 33'b1;
wire LT = (aluIn1[31] ^ aluIn2[31]) ? aluIn1[31] : aluMinus[32];
wire LTU = aluMinus[32];
wire EQ = (aluMinus[31:0] == 0);

ram_idx_calc:
wire [IDXBITS-1:0] seed_idx    = 32'd[[[ core_memory_nonlinear_seed ]]] | 1'b1;

wire [IDXBITS-1:0] idx         = logical_idx * seed_idx;
wire [IDXBITS-1:0] load_idx    = logical_load_idx * seed_idx;

decrypt_instruction:
wire [31:0] key_input;
wire [31:0] instr_key;
wire [31:0] instr_dec;

assign key_input = 32'd[[[ core_crypt_seed ]]] + PC;
assign instr_key = (key_input * 32'd1732714) + 32'd1182730741;
assign instr_dec = mem_rdata ^ instr_key;

decrypt_ram:
// decrypt ram
    mem_rdata = ram[idx] ^ (
        ((32'd[[[ core_ram_seed ]]] + logical_idx) * 32'd1732714) + 32'd1182730741
    );

encrypt_ram:
// Encrypt ram
wire [31:0] mem_wdata_enc = mem_wdata ^ (
    ((32'd[[[ core_ram_seed ]]] + logical_idx) * 32'd1732714) + 32'd1182730741
);

ebpf_interpreter_decrypt:
inline void decrypt_instr(u32 addr, u8* data, u8* dest) {
    u32* w = (u32*)(data);
    u32* d = (u32*)(dest);
    d[0] = w[0];
    d[1] = w[1];
}
